ee:variables.ee:set-variable:
%dw 2.0
output application/json
import toBase64 from dw::core::Binaries
---
{
	"method": Mule::p('b2b-p21-sys-api.view.method'),
//	"host": Mule::p('b2b-p21-sys-api.host'),
//	"port": Mule::p('b2b-p21-sys-api.port'),
	"host":"localhost",
	"port": "8092",
	"basePath": Mule::p('b2b-p21-sys-api.basePath'),
	"path": Mule::p('b2b-p21-sys-api.view.path'),
	"headers": {
		"x-correlation-id": vars.integration.correlationId
	},
	"queryParams": {
		"transactionType": Mule::p('b2b-p21-sys-api.transactionType.salesOrder'),
		"purpose": Mule::p('b2b-p21-sys-api.purpose.total'),
		"businesskey": vars.initialPayload.b2bMessage.header.poNumber[0] default null,
		"ediRefId" : (payload[0].b2bMessage.header.partyInformation
    filter ($.qualifier == "BY"))[0].identificationCode default ""
	},
	"uriParams": {
	},
	"body": {
	},
	"untilsuccessful": {
		"maxRetries": Mule::p('b2b-p21-sys-api.view.untilsuccessful.maxRetries'),
		"interval": Mule::p('b2b-p21-sys-api.view.untilsuccessful.interval')
	}
}

%dw 2.0
output application/json

var response = vars.salesOrderLookUpData

var hasDuplicate = sizeOf(response) > 1 and (sizeOf(response filter ((item) -> item.po_no != "")) > 0)
var errorCount = if (hasDuplicate)
  1
else
  0
output application/json  
---
{
  isValid: errorCount == 0,
  validationErrors:
    if (hasDuplicate)
      {
        duplicatePo:[ "The incoming Purchase Order already exists in the system for the given customer and ship-to combination."],

      }
    else
     {}
}

%dw 2.0
output application/json
import toBase64 from dw::core::Binaries
var inputPayload = vars.initialPayload[0]
var viewData = vars.salesOrderLookUpData[0]
---
{
	"method": Mule::p('b2b-p21-sys-api.transaction.method'),
//	"host": Mule::p('b2b-p21-sys-api.host'),
//	"port": Mule::p('b2b-p21-sys-api.port'),
	"host": "localhost",
	"port": "8092",
	"basePath": Mule::p('b2b-p21-sys-api.basePath'),
	"path": Mule::p('b2b-p21-sys-api.transaction.path'),
	"headers": {
		"x-correlation-id": vars.integration.correlationId
	},
	"queryParams": {
		"transactionType": Mule::p('b2b-p21-sys-api.transactionType.salesOrder'),
		"processingMode": "direct",
		"checkType": "catalogPrice",
		"companyId": viewData.company_id,
		"customerId": viewData.customer_id,
		"salesLocId": viewData.preferred_location_id
	},
	"uriParams": {
	},
	"untilsuccessful": {
		"maxRetries": Mule::p('b2b-p21-sys-api.transaction.untilsuccessful.maxRetries'),
		"interval": Mule::p('b2b-p21-sys-api.transaction.untilsuccessful.interval')
	},
	"body": {
		UseCodeValues: true,
		IgnoreDisabled: true,
		Transactions: [{
			Status: "New",
			DataElements: [{
				ArrayOfItemPriceInfo: {
					ItemPriceInfo: inputPayload.b2bMessage.detail.itemDetails map (item) -> {
						ItemId: item.buyersPartNumber,
						SourceLocId: viewData.preferred_location_id as String,
						CustomerPartNo: item.buyersPartNumber,
						UnitQuantity: item.quantityOrdered,
						UnitSize: 1,
						UOM: item.unitOfMeasurementCode
					}
				}
			}]
		}]
	}
}

%dw 2.0
output application/json

var debug = true

var ediItems =
    payload[0].b2bMessage.detail.itemDetails

var salesPricingItems =
    if (vars.salesPricing.ArrayOfItemPrice.ItemPrice is Array)
        vars.salesPricing.ArrayOfItemPrice.ItemPrice
    else
        [vars.salesPricing.ArrayOfItemPrice.ItemPrice]

var lineComparisons =
    ediItems map ((poItem, index) ->

        do {

            var matchedP21Item =
                (salesPricingItems
                    filter ((item) -> item.ItemId == poItem.buyersPartNumber))[0]

            var ediItemId = poItem.buyersPartNumber
            var p21ItemId = matchedP21Item.ItemId default null

            var ediUom = poItem.unitOfMeasurementCode
            var p21Uom = matchedP21Item.UOM default null

            var ediQty = poItem.quantityOrdered
            var p21AvailableQty =
                (matchedP21Item.QuantityAvailable default 0) as Number

            var ediUnitPrice = poItem.unitPrice
            var p21UnitPrice =
                (matchedP21Item.UnitPrice default 0) as Number

            var ediExtendedPrice =
                ediQty * ediUnitPrice

            var p21ExtendedPrice =
                (matchedP21Item.ExtendedPrice default 0) as Number

            var itemMatched =
                ediItemId == p21ItemId

            var uomMatched =
                ediUom == p21Uom

            var priceMatched =
                ediUnitPrice == p21UnitPrice

            var quantityAvailable =
                p21AvailableQty >= ediQty

            var overallStatus =
                if (
                    itemMatched
                    and uomMatched
                    and priceMatched
                    and quantityAvailable
                )
                "VALID"
                else
                "FAILED"

            var requiresP21Override =
                overallStatus == "FAILED"

            ---
            {
                lineNo: poItem.lineNo,

                validationSummary: {
                    itemMatched: itemMatched,
                    uomMatched: uomMatched,
                    priceMatched: priceMatched,
                    quantityAvailable: quantityAvailable,
                    overallStatus: overallStatus,
                    requiresP21Override: requiresP21Override
                },

                headerLevelNote:
                    if (requiresP21Override)
                        "Line " ++ poItem.lineNo ++
                        " | Item: " ++ ediItemId ++
                        " | EDI Price: " ++ (ediUnitPrice as String) ++
                        " | P21 Price: " ++ (p21UnitPrice as String)
                    else
                        null,

                orderLineNotes:
                    if (requiresP21Override)
                        {
                            lineNo: poItem.lineNo,
                            notes: {
                                OrderLineNote: {
                                    Topic: "LINE LEVEL VALIDATION",
                                    Note: "Line Item Id is incorrect or pricing mismatch found",
                                    NotepadClassId: "ITEMS",
                                    Mandatory: "Y"
                                }
                            }
                        }
                    else
                        null,

                finalOrderValues: {

                    itemId:
                        if (requiresP21Override)
                            p21ItemId
                        else
                            ediItemId,

                    quantity:
                        ediQty,

                    unitOfMeasure:
                        if (requiresP21Override)
                            p21Uom
                        else
                            ediUom,

                    unitPrice:
                        if (requiresP21Override)
                            p21UnitPrice
                        else
                            ediUnitPrice,

                    extendedPrice:
                        if (requiresP21Override)
                            p21ExtendedPrice
                        else
                            ediExtendedPrice
                }
            }
        }
    )

var failedLines =
    lineComparisons filter (
        $.validationSummary.overallStatus == "FAILED"
    )

var headerLevelNotes =
    failedLines
        map ($.headerLevelNote)
        joinBy " || "

var orderLineSection =
    failedLines
        map ($.orderLineNotes)

var validationSummary = {
    totalLines: sizeOf(lineComparisons),
    failedLines: sizeOf(failedLines),
    successfulLines:
        sizeOf(lineComparisons) - sizeOf(failedLines),

    overallStatus:
        if (sizeOf(failedLines) > 0)
            "FAILED"
        else
            "VALID"
}

---
{
    validationSummary: validationSummary,

    notesPreparation: {
        addHeaderLevelNote:
            sizeOf(failedLines) > 0,

        headerLevelNote:
            headerLevelNotes
    },

    orderLineSection: orderLineSection,

    lineComparisons: lineComparisons
}

%dw 2.0
output application/json
import toBase64 from dw::core::Binaries

var inputPayload = vars.initialPayload[0].b2bMessage

var header =
    inputPayload.header

var orderLines =
    inputPayload.detail.itemDetails

var salesPricing =
    vars.salesPricing.ArrayOfItemPrice.ItemPrice

var salesOrderLookUpData =
    vars.salesOrderLookUpData[0]

var validationData =
    vars.isValid

var pricingLines =
    if (salesPricing is Array)
        salesPricing
    else
        [salesPricing]

var hasHeaderErrors =
    validationData.validationSummary.overallStatus == "FAILED"

var headerMessage =
    if (hasHeaderErrors)
        validationData.notesPreparation.headerLevelNote
    else
        "Purchase Order validation completed successfully. No mismatches found."

---
{
	"method": Mule::p('b2b-p21-sys-api.transaction.method'),
//	"host": Mule::p('b2b-p21-sys-api.host'),
//	"port": Mule::p('b2b-p21-sys-api.port'),
	"host": "localhost",
	"port": "8092",
	"basePath": Mule::p('b2b-p21-sys-api.basePath'),
	"path": Mule::p('b2b-p21-sys-api.transaction.path'),
	"headers": {
		"x-correlation-id": vars.integration.correlationId
	},
	"queryParams": {
		"transactionType": Mule::p('b2b-p21-sys-api.transactionType.salesOrder'),
		"processingMode": "direct",
		"checkType": "default",

	},
	"uriParams": {
	},
	"untilsuccessful": {
		"maxRetries": Mule::p('b2b-p21-sys-api.transaction.untilsuccessful.maxRetries'),
		"interval": Mule::p('b2b-p21-sys-api.transaction.untilsuccessful.interval')
	},
	"body": {
  UseCodeValues: true,

  IgnoreDisabled: true,

  Transactions: [
    {
      Status: "New",

      DataElements: [
        {
          Order: {

            CustomerId:
              salesOrderLookUpData.customer_id,

            CompanyId:
              salesOrderLookUpData.company_id,

            LocationId:
              pricingLines[0].LocationId default "",

            ShipToId:
              salesOrderLookUpData.ship_to_id,

            PoNo:
              header.poNumber,

            ContactId:
              salesOrderLookUpData.edi_default_contact_id default "",

            Taker:
              salesOrderLookUpData.edi_default_contact_id
              default "MULESOFTINT",

            Quote: "N",

            Approved: "false",

            Notes: {
              OrderNote: {
                Topic:
                  if (hasHeaderErrors)
                    "HEADER LEVEL VALIDATION"
                  else
                    "PO VALIDATION SUCCESS",

                Note:
                  headerMessage,

                NotepadClassId: "ITEMS",

                Mandatory:
                  if (hasHeaderErrors)
                    "true"
                  else
                    "false"
              }
            },

            Lines: {
              OrderLine:

                orderLines map ((detail, index) -> do {

                  var matchedPricing =
                    pricingLines filter (
                      ($.ItemId default "")
                      ==
                      (detail.buyersPartNumber default "")
                    )

                  var pricing =
                    if (sizeOf(matchedPricing) > 0)
                      matchedPricing[0]
                    else
                      {}

                  var matchedLineNote =
                    (
                      validationData.lineComparisons
                      filter (
                        (($.lineNo default "") as String)
                        ==
                        ((detail.lineNo default "") as String)
                      )
                    )[0] default null

                  var hasLineError =
                    matchedLineNote != null
                    and
                    matchedLineNote.orderLineNotes != null

                  ---
                  {

                    (Notes:
                      matchedLineNote.orderLineNotes.notes)
                      if (hasLineError),

                    LineNo:
                      detail.lineNo,

                    ItemId:
                      pricing.ItemId default "",

                    ItemDesc:
                      (detail.descriptions[0].description default "")
                      ++ " "
                      ++
                      (detail.manufacturersPartNumber default ""),

                    ExtendedDesc:
                      detail.descriptions[0].description default "",

                    UnitQuantity:
                      detail.quantityOrdered as String,

                    UnitOfMeasure:
                      pricing.UOM default "",

                    UnitPrice:
                      pricing.UnitPrice default "",

                    QtyOrdered:
                      detail.quantityOrdered as String,

                    ExtendedPrice:
                      pricing.ExtendedPrice default "",

                    SourceLocId:
                      pricing.LocationId default ""
                  }
                })
            }
          }
        }
      ]
    }
  ]
}
}
